const isPlaceholderConfig = firebaseConfig.apiKey.includes('placeholder');

const DevInProgressPopup: React.FC<{ featureName: string; onClose: () => void }> = ({ featureName, onClose }) => (
    <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center z-50 animate-fade-in p-4">
        <div className="bg-white dark:bg-gray-800 p-6 sm:p-8 rounded-2xl shadow-lg max-w-sm mx-auto text-center">
            <div className="mx-auto flex items-center justify-center h-16 w-16 rounded-full bg-yellow-100 dark:bg-yellow-900/40 mb-5">
                <WrenchIcon className="h-9 w-9 text-yellow-600 dark:text-yellow-400" />
            </div>
            <h2 className="text-xl sm:text-2xl font-bold text-gray-800 dark:text-gray-100 mb-3">Feature Under Development</h2>
            <p className="text-sm sm:text-base text-gray-600 dark:text-gray-400 mb-6">
                The "{featureName}" feature is not yet implemented. Please check back later!
            </p>
            <button
                onClick={onClose}
                className="w-full bg-indigo-600 text-white font-bold py-3 px-4 rounded-lg hover:bg-indigo-700 transition-colors shadow-md"
            >
                Got it
            </button>
        </div>
    </div>
);

export default function App() {
    const [theme, setTheme] = useState<'light' | 'dark'>(() => {
        if (localStorage.getItem('theme') === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
          return 'dark';
        }
        return 'light';
    });

    type Role = 'academy' | 'student' | 'staff';

    const [page, setPage] = useState(() => {
        if (localStorage.getItem('onboardingCompleted')) {
            return 'role-selection';
        }
        return 'onboarding';
    });
    const [loginPageRole, setLoginPageRole] = useState<Role>('academy');
    const [pageParams, setPageParams] = useState<{[key: string]: any}>({});
    const [currentUser, setCurrentUser] = useState<CurrentUser | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [isNavOpen, setIsNavOpen] = useState(false);
    const [authError, setAuthError] = useState<string | null>(null);
    const [systemLogoUrl, setSystemLogoUrl] = useState<string | null>(null);

    // Data state
    const [academy, setAcademy] = useState<Academy | null>(null);
    const [batches, setBatches] = useState<Batch[]>([]);
    const [students, setStudents] = useState<Student[]>([]);
    const [staff, setStaff] = useState<Staff[]>([]);
    const [staffAttendance, setStaffAttendance] = useState<StaffAttendance[]>([]);
    const [feeCollections, setFeeCollections] = useState<FeeCollection[]>([]);
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [exams, setExams] = useState<Exam[]>([]);
    const [enquiries, setEnquiries] = useState<Enquiry[]>([]);
    const [studyMaterials, setStudyMaterials] = useState<StudyMaterial[]>([]);
    const [homework, setHomework] = useState<Homework[]>([]);
    const [quizzes, setQuizzes] = useState<Quiz[]>([]);
    const [quizSubmissions, setQuizSubmissions] = useState<QuizSubmission[]>([]);
    const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
    const [tasks, setTasks] = useState<Task[]>([]);
    const [notices, setNotices] = useState<Notice[]>([]);
    const [transportRoutes, setTransportRoutes] = useState<TransportRoute[]>([]);
    const [salaryPayments, setSalaryPayments] = useState<SalaryPayment[]>([]); 
    const [todaysAttendance, setTodaysAttendance] = useState<Record<string, any>>({});
    const [todaysSchedule, setTodaysSchedule] = useState<DailySchedule | null | 'loading'>('loading');

    // Page-specific state
    const [selectedBatchId, setSelectedBatchId] = useState<string | null>(null);
    const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
    const [selectedStaffId, setSelectedStaffId] = useState<string | null>(null);
    const [selectedExamId, setSelectedExamId] = useState<string | null>(null);
    const [selectedEnquiryId, setSelectedEnquiryId] = useState<string | null>(null);
    const [selectedStudyMaterialId, setSelectedStudyMaterialId] = useState<string | null>(null);
    const [selectedHomeworkId, setSelectedHomeworkId] = useState<string | null>(null);
    const [selectedQuizId, setSelectedQuizId] = useState<string | null>(null);
    const [studentListFilter, setStudentListFilter] = useState('all');
    const [selectedTransportRouteId, setSelectedTransportRouteId] = useState<string | null>(null);

    // UI State
    const [connectionError, setConnectionError] = useState<string | null>(null);
    const [isOffline, setIsOffline] = useState(!navigator.onLine);
    const [showConsent, setShowConsent] = useState(!localStorage.getItem('dataConsentAccepted'));
    const [showDevPopup, setShowDevPopup] = useState<string | null>(null);
    const [imageToView, setImageToView] = useState<string | null>(null);
    const [isChatbotOpen, setIsChatbotOpen] = useState(false);

    useEffect(() => {
        const initializeApp = async () => {
            if (Capacitor.isNativePlatform()) {
                await StatusBar.setStyle({ style: Style.Light });
                await CapSplashScreen.hide();
            }
        };
        initializeApp();
    }, []);

    useEffect(() => {
        if (isPlaceholderConfig) return;
        const unsubConfig = onSnapshot(doc(db, 'system_config', 'main'), (docSnap) => {
            if (docSnap.exists()) {
                setSystemLogoUrl(docSnap.data().logoUrl || null);
            }
        });
        return () => unsubConfig();
    }, []);

    useEffect(() => {
        window.scrollTo(0, 0);
    }, [page]);

    const isDemoMode = (currentUser?.role === 'admin' && currentUser.data.id === 'demo-academy-id') ||
        ((currentUser?.role === 'student' || currentUser?.role === 'staff') && currentUser.academyId === 'DEMO');

    useEffect(() => {
        if (theme === 'dark') {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [theme]);

    const handleToggleTheme = () => {
        setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
    };

    const handleNavigate = (page: string, params?: {[key: string]: any}) => {
        setPageParams(params || {});
        setPage(page);
    };

    useEffect(() => {
        const handleOnline = () => setIsOffline(false);
        const handleOffline = () => setIsOffline(true);
        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);
        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    useEffect(() => {
        if (isPlaceholderConfig) {
            setIsLoading(false);
            if (!localStorage.getItem('onboardingCompleted')) setPage('onboarding');
            else if (localStorage.getItem('lastSelectedRole')) {
                 setLoginPageRole(localStorage.getItem('lastSelectedRole') as Role);
                 setPage('login');
            } else setPage('role-selection');
            return;
        }

        const unsubscribe = auth.onAuthStateChanged(async (user: firebase.User | null) => {
             try {
                if (user) {
                    if (user.isAnonymous) return;
                    const userDocRef = doc(db, "users", user.uid);
                    const userDocSnap = await getDoc(userDocRef);
                    if (userDocSnap.exists()) {
                        const userData = userDocSnap.data();
                        if (userData.role === 'admin' && userData.academyId) {
                            const academyDocRef = doc(db, "academies", userData.academyId);
                            const academyDocSnap = await getDoc(academyDocRef);
                            if (academyDocSnap.exists()) {
                                const academyData = { id: academyDocSnap.id, ...academyDocSnap.data() } as Academy;
                                setAcademy(academyData);
                                setCurrentUser({ role: 'admin', data: academyData });
                                setPage('dashboard');
                            } else {
                                setAuthError("Your academy data is missing.");
                                setPage('complete-registration');
                            }
                        } else {
                            setAuthError("Your account is not configured as an admin account.");
                            await auth.signOut();
                        }
                    } else {
                        const instituteName = sessionStorage.getItem('registration_institute_name');
                        if (instituteName) {
                             setPage('complete-registration');
                        } else {
                             setPage('complete-registration');
                        }
                    }
                } else {
                    setCurrentUser(null);
                    setAcademy(null);
                    if (localStorage.getItem('onboardingCompleted')) {
                         setPage(localStorage.getItem('lastSelectedRole') ? 'login' : 'role-selection');
                    } else {
                        setPage('onboarding');
                    }
                }
            } catch (error) {
                console.error("Auth error", error);
            } finally {
                setIsLoading(false);
            }
        });
        return () => unsubscribe();
    }, []);

    useEffect(() => {
        if (!currentUser || isPlaceholderConfig || isDemoMode) {
            if (isDemoMode) {
                setAcademy({ id: 'demo', academyId: 'DEMO', name: 'Demo Academy', adminUid: 'demo', adminEmail: 'demo@test.com', status: 'active', subscriptionStatus: 'active' });
                setBatches(demoBatches);
                setStudents(demoStudents);
                setStaff(demoStaff);
                setStaffAttendance(demoStaffAttendance);
                setFeeCollections([]);
                setTransactions(demoTransactions);
                setExams([]);
                setEnquiries(demoEnquiries);
                setStudyMaterials([]);
                setHomework([]);
                setQuizzes([]);
                setLeaveRequests([]);
                setTasks([]);
                setNotices([]);
                setTransportRoutes(demoTransportRoutes);
                setSalaryPayments([]);
            }
            return;
        };

        const academyId = (currentUser.role === 'admin') ? currentUser.data.id : currentUser.academyId;
        if (!academyId) return;

        const unsubscribers: (() => void)[] = [];

        const academyDocRef = doc(db, 'academies', academyId);
        const unsubAcademy = onSnapshot(academyDocRef, (docSnap) => {
            if (docSnap.exists()) {
                setAcademy({ id: docSnap.id, ...docSnap.data() } as Academy);
            }
        });
        unsubscribers.push(unsubAcademy);

        const collections = ['batches', 'students', 'staff', 'fees', 'transactions', 'exams', 'enquiries', 'studyMaterial', 'homework', 'quizzes', 'leaveRequests', 'tasks', 'notices', 'transportRoutes', 'staffAttendance', 'salaryPayments'];

        const setters: any = {
            batches: setBatches, students: setStudents, staff: setStaff, fees: setFeeCollections,
            transactions: setTransactions, exams: setExams, enquiries: setEnquiries, studyMaterial: setStudyMaterials,
            homework: setHomework, quizzes: setQuizzes, leaveRequests: setLeaveRequests, tasks: setTasks,
            notices: setNotices, transportRoutes: setTransportRoutes, staffAttendance: setStaffAttendance, salaryPayments: setSalaryPayments
        };

        collections.forEach(coll => {
             const collRef = collection(db, `academies/${academyId}/${coll}`);
             unsubscribers.push(onSnapshot(collRef, (snap) => {
                 setters[coll](snap.docs.map(d => ({ id: d.id, ...d.data() })));
             }));
        });

        return () => unsubscribers.forEach(u => u());
    }, [currentUser, isDemoMode]);

    const handleLogin = (user: CurrentUser) => {
        setAuthError(null);
        setCurrentUser(user);
        if (user.role === 'admin') setAcademy(user.data);
        setPage('dashboard');
    };

    const handleLogout = async () => {
        setIsNavOpen(false);
        if(!isDemoMode) await auth.signOut();
        setCurrentUser(null);
        setAcademy(null);
        localStorage.removeItem('lastSelectedRole');
        setPage('role-selection');
    };

    const handleShowDevPopup = (name: string) => setShowDevPopup(name);
    const handleCompleteRegistration = async (name: string) => {};

    const handleToggleStudentStatus = async (studentId: string) => {
        if (isDemoMode) {
             setStudents(prev => prev.map(s => s.id === studentId ? { ...s, isActive: !s.isActive } : s));
             return;
        }
        if (!academy) return;
        const student = students.find(s => s.id === studentId);
        if (!student) return;

        try {
            await updateDoc(doc(db, `academies/${academy.id}/students`, studentId), {
                isActive: !student.isActive
            });
        } catch (error) {
            console.error("Error toggling student status:", error);
            alert("Failed to update status.");
        }
    };

    const handleBulkSaveStudents = async (studentsData: Omit<Student, 'id' | 'isActive'>[]) => {
        if (!academy || isDemoMode) {
            throw new Error("Cannot save in demo mode.");
        }

        const chunkSize = 400;
        for (let i = 0; i < studentsData.length; i += chunkSize) {
            const chunk = studentsData.slice(i, i + chunkSize);
            const batch = writeBatch(db);
            const batchCounts: Record<string, number> = {};

            chunk.forEach(studentData => {
                const studentRef = doc(collection(db, `academies/${academy.id}/students`));
                const dataToSave = { ...studentData, isActive: true };
                batch.set(studentRef, dataToSave);

                studentData.batches.forEach(bName => {
                    const batchObj = batches.find(b => b.name.trim().toLowerCase() === bName.trim().toLowerCase());
                    if (batchObj) {
                        batchCounts[batchObj.id] = (batchCounts[batchObj.id] || 0) + 1;
                    }
                });
            });

            Object.entries(batchCounts).forEach(([batchId, count]) => {
                 batch.update(doc(db, `academies/${academy.id}/batches`, batchId), { currentStudents: increment(count) });
            });

            await batch.commit();
        }
    };

    const findSelected = <T extends {id: string}>(list: T[], id: string | null) => id ? list.find(i => i.id === id) : undefined;
    const selectedBatch = findSelected(batches, selectedBatchId);
    const selectedStudent = findSelected(students, selectedStudentId);
    const selectedStaff = findSelected(staff, selectedStaffId);
    const selectedExam = findSelected(exams, selectedExamId);
    const selectedEnquiry = findSelected(enquiries, selectedEnquiryId) || (pageParams.enquiryId && findSelected(enquiries, pageParams.enquiryId));
    const selectedHomework = findSelected(homework, selectedHomeworkId);
    const selectedQuiz = findSelected(quizzes, selectedQuizId);
    const selectedTransportRoute = findSelected(transportRoutes, selectedTransportRouteId);
    const selectedStudyMaterial = findSelected(studyMaterials, selectedStudyMaterialId);

    const handleSaveBatch = async (data: any, id?: string) => {}; 
    const handleSaveStudent = async (data: any, id?: string) => {}; 
    const handleUpdateStudent = async (data: any) => {};
    const handleSaveFeePayment = async (data: any) => {};
    const handleDeleteFeeCollection = async (id: string) => {};
    const handleUpdateFeeCollection = async (id: string, data: any) => {};
    const handleSaveStaff = async (data: any) => {};
    const handleToggleStaffStatus = async (id: string) => {};
    const handleUpdateStaffBatchAccess = async (id: string, data: any) => {};
    const handleSaveAcademyDetails = async (data: any) => {};
    const handleSaveSchedule = async (date: string, batchId: string, items: any) => {};
    const handleSubscribe = async (plan: any, months: any, details: any) => {};
    const handleSaveTransaction = async (data: any, id?: string) => {};
    const handleUpdateTransaction = async (id: string, data: any) => {};
    const handleDeleteTransaction = async (id: string) => {};
    const handleSaveExam = async (data: any) => {};
    const handlePublishExam = async (id: string, status: any) => {};
    const handleSaveEnquiry = async (data: any) => {};
    const handleDeleteEnquiry = async (id: string) => {};
    const handleSaveStudyMaterial = async (data: any) => {};
    const handleDeleteStudyMaterial = async (data: any) => {};
    const handleSaveHomework = async (data: any) => {};
    const handleDeleteHomework = async (data: any) => {};
    const handleSaveQuiz = async (data: any) => {};
    const handleDeleteQuiz = async (id: string) => {};
    const handleUpdateLeaveStatus = async (id: string, status: any) => {};
    const handleSaveTask = async (data: any, id?: string) => {};
    const handleToggleTaskStatus = async (id: string, status: any) => {};
    const handleDeleteTask = async (id: string) => {};
    const handleSaveNotice = async (data: any, id?: string) => {};
    const handleDeleteNotice = async (data: any) => {};
    const handleSaveTransportRoute = async (data: any, id?: string) => {};
    const handleDeleteTransportRoute = async (id: string) => {};
    const handleMapStudentsToRoute = async (id: string, assigned: any, unassigned: any) => {};
    const handleSaveQuizSubmission = async (id: string, answers: any) => {};
    const handleSaveStaffAttendance = async (data: any, id?: string) => {};
    const handleDeleteStaffAttendance = async (id: string) => {};
    const handleSaveSalaryPayment = async (data: any) => {};
    const handleDeleteSalaryPayment = async (id: string) => {};


    const renderPage = () => {
        const student = currentUser?.role === 'student' ? currentUser.data : null;

        switch (page) {
            case 'dashboard':
                if (currentUser?.role === 'admin') return <Dashboard onNavigate={setPage} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                if (currentUser?.role === 'student') return <StudentDashboardPage student={currentUser.data} academy={academy!} feeCollections={feeCollections} batches={batches} onNavigate={setPage} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                if (currentUser?.role === 'staff') return <StaffDashboardPage onNavigate={setPage} academy={academy!} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                return null;

            case 'student-options':
                return <StudentOptionsPage onBack={() => setPage('dashboard')} onNavigate={setPage} isStaffView={currentUser?.role === 'staff'} onShowDevPopup={handleShowDevPopup} />;

            case 'active-students':
                return <ActiveStudentsPage onBack={() => setPage('student-options')} students={students} batches={batches} onToggleStudentStatus={handleToggleStudentStatus} onEditStudent={(id) => { setSelectedStudentId(id); setPage('edit-student'); }} onViewStudent={(id) => { setSelectedStudentId(id); setPage('student-details')}} initialFilter={studentListFilter} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined}/>;

            case 'bulk-upload-students':
                return <BulkUploadPage onBack={() => setPage('student-options')} onSave={handleBulkSaveStudents} batches={batches} isDemoMode={isDemoMode || false} />;

            case 'student-details':
                const currentStudent = students.find(s => s.id === selectedStudentId);
                if (!currentStudent) return <Dashboard onNavigate={setPage} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                return <StudentDetailsPage onBack={() => setPage('active-students')} student={currentStudent} feeCollections={feeCollections.filter(f => f.studentId === currentStudent.id)} academyId={academy!.id} onSavePayment={handleSaveFeePayment} transportRoutes={transportRoutes} onShowImage={setImageToView} academy={academy!} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} currentUserRole={currentUser?.role === 'admin' || currentUser?.role === 'staff' ? currentUser?.role : undefined} />;

            case 'edit-student':
                if (selectedStudentId) {
                    const studentToEdit = students.find(s => s.id === selectedStudentId);
                    if(studentToEdit) return <EditStudentPage onBack={() => setPage('active-students')} student={studentToEdit} batches={batches} onUpdate={handleUpdateStudent} />;
                }
                return null;

            case 'new-student':
                const enquiry = selectedEnquiryId ? enquiries.find(e => e.id === selectedEnquiryId) : null;
                return <NewStudentPage onBack={() => { setSelectedEnquiryId(null); setPage('student-options'); }} onSave={handleSaveStudent} batches={batches} academyId={academy!.academyId} enquiryData={enquiry} students={students} academy={academy!} />;

            case 'inactive-students':
                return <InactiveStudentsPage onBack={() => setPage('student-options')} students={students} batches={batches} onToggleStudentStatus={handleToggleStudentStatus} />;

            case 'birthday-list':
                return <BirthdayListPage onBack={() => setPage('student-options')} students={students} />;

            case 'registration-form-list':
                return <RegistrationFormListPage onBack={() => setPage('student-options')} students={students} onSelectStudent={(id) => { setSelectedStudentId(id); setPage('registration-form-view'); }} />;

