    if (isLoading) return <SplashScreen />;
    if (!currentUser) return (
        <div className="min-h-screen flex flex-col">
            {isPlaceholderConfig && <ConfigurationWarning />}
            {page === 'onboarding' && <OnboardingPage onComplete={() => { localStorage.setItem('onboardingCompleted', 'true'); setPage('role-selection'); }} />}
            {page === 'role-selection' && <RoleSelectionPage onSelectRole={(role) => { localStorage.setItem('lastSelectedRole', role); setLoginPageRole(role); setPage('login'); }} onBack={() => { if(window.history.length > 1) window.history.back(); }} />}
            {page === 'register' && <RegisterPage onNavigateToLogin={() => setPage('login')} />}
            {page === 'complete-registration' && <CompleteRegistrationPage onComplete={handleCompleteRegistration} onLogout={handleLogout} userEmail={auth.currentUser?.email || ''} externalError={authError} clearExternalError={() => setAuthError(null)} />}
            {page !== 'onboarding' && page !== 'role-selection' && page !== 'register' && page !== 'complete-registration' &&
                <LoginPage onLogin={handleLogin} onNavigateToRegister={() => setPage('register')} externalError={authError} clearExternalError={() => setAuthError(null)} initialRole={loginPageRole} onGoBack={() => { localStorage.removeItem('lastSelectedRole'); setPage('role-selection'); }} systemLogoUrl={systemLogoUrl} />
            }
        </div>
    );

    return (
        <div className={`min-h-screen font-sans ${theme} bg-gray-100 dark:bg-gray-900`}>
             {isPlaceholderConfig && page !== 'onboarding' && <ConfigurationWarning />}
             {connectionError && <ConnectionErrorBanner message={connectionError} onClose={() => setConnectionError(null)} />}
             {isOffline && <OfflineIndicator />}

             {currentUser?.role === 'admin' && academy && (
                 <>
                     {page === 'dashboard' && <Header academy={academy} onLogout={handleLogout} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onNavigate={setPage} notificationCount={0} />}
                     <SideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} />
                     <main>{renderPage()}</main>
                     {page === 'dashboard' && <BottomNav onNavigate={setPage} activePage={page} onOpenChatbot={() => setIsChatbotOpen(true)} />}
                 </>
            )}

            {currentUser?.role === 'student' && academy && (
                <>
                    <StudentSideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} systemLogoUrl={systemLogoUrl} />
                    <main>{renderPage()}</main>
                </>
            )}

            {currentUser?.role === 'staff' && academy && (
                <>
                    {page === 'dashboard' && <StaffHeader staffName={currentUser.data.name} academyName={academy.name} onLogout={handleLogout} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onNavigate={setPage} notificationCount={0} />}
                    <StaffSideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} />
                    <main>{renderPage()}</main>
                </>
            )}

            {showConsent && <DataConsentModal onAccept={() => { localStorage.setItem('dataConsentAccepted', 'true'); setShowConsent(false); }} />}
            {showDevPopup && <DevInProgressPopup featureName={showDevPopup} onClose={() => setShowDevPopup(null)} />}
            {imageToView && <FullScreenImageViewer src={imageToView} alt="Full screen view" onClose={() => setImageToView(null)} />}
             {isChatbotOpen && academy && (
                <AIChatbot
                    isOpen={isChatbotOpen}
                    onClose={() => setIsChatbotOpen(false)}
                    onNavigate={(page: string) => {
                        handleNavigate(page);
                        setIsChatbotOpen(false);
                    }}
                    students={students}
                    feeCollections={feeCollections}
                    batches={batches}
                    academyId={academy.id}
                />
            )}
        </div>
    );
}

