    const handleBulkSaveStudents = async (studentsData: Omit<Student, 'id' | 'isActive'>[]) => {
        if (!academy || isDemoMode) {
            throw new Error("Cannot save in demo mode.");
        }

        // Process in chunks of 400 to respect Firestore batch limit of 500
        const chunkSize = 400;
        for (let i = 0; i < studentsData.length; i += chunkSize) {
            const chunk = studentsData.slice(i, i + chunkSize);
            const batch = writeBatch(db);

            // To aggregate batch counts for update
            const batchCounts: Record<string, number> = {};

            chunk.forEach(studentData => {
                const studentRef = doc(collection(db, `academies/${academy.id}/students`));
                const dataToSave = { ...studentData, isActive: true };
                batch.set(studentRef, dataToSave);

                // Count students per batch to update batch stats
                studentData.batches.forEach(bName => {
                    // Match batch name to ID. Note: This assumes batch names are unique and match existing batches.
                    // If a batch doesn't exist, we skip counting it here (it won't be created automatically).
                    const batchObj = batches.find(b => b.name.trim().toLowerCase() === bName.trim().toLowerCase());
                    if (batchObj) {
                        batchCounts[batchObj.id] = (batchCounts[batchObj.id] || 0) + 1;
                    }
                });
            });

            // Add batch updates to the write batch
            Object.entries(batchCounts).forEach(([batchId, count]) => {
                 batch.update(doc(db, `academies/${academy.id}/batches`, batchId), { currentStudents: increment(count) });
            });

            await batch.commit();
        }
    };

