            case 'edit-batch':
                const batchToEdit = batches.find(b => b.id === selectedBatchId);
                if(batchToEdit) return <EditBatchPage onBack={() => setPage('batches')} onSave={handleSaveBatch} batch={batchToEdit} />;
                return null;

            case 'select-batch-attendance':
                return <SelectBatchForAttendancePage onBack={() => setPage('dashboard')} batches={batches} onSelectBatch={(id) => { setSelectedBatchId(id); setPage('take-attendance'); }} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} academyId={academy!.id} />;

            case 'take-attendance':
                const attendanceBatch = batches.find(b => b.id === selectedBatchId);
                if (attendanceBatch) return <TakeAttendancePage onBack={() => setPage('select-batch-attendance')} batch={attendanceBatch} students={students} academy={academy!} isDemoMode={isDemoMode} onShowImage={setImageToView} />;
                return null;

            case 'fees-options':
                return <FeesOptionsPage onBack={() => setPage('dashboard')} onNavigate={setPage} />;

            case 'select-batch-for-fees':
                return <SelectBatchForFeesPage onBack={() => setPage('fees-options')} batches={batches} onSelectBatch={(id) => { setSelectedBatchId(id); setPage('select-student-for-fees'); }} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;

            case 'select-student-for-fees':
                const feesBatch = batches.find(b => b.id === selectedBatchId);
                if (feesBatch) return <SelectStudentForFeesPage onBack={() => setPage('select-batch-for-fees')} batch={feesBatch} students={students} onSelectStudent={(id) => { setSelectedStudentId(id); setPage('student-fee-details'); }} />;
                return null;

            case 'student-fee-details':
                const feeStudent = students.find(s => s.id === selectedStudentId);
                if (feeStudent) return <StudentFeeDetailsPage onBack={() => setPage('select-student-for-fees')} student={feeStudent} feeCollections={feeCollections.filter(f => f.studentId === feeStudent.id)} onSavePayment={handleSaveFeePayment} academy={academy!} />;
                return null;

            case 'fee-collection-report':
                return <FeeCollectionReportPage onBack={() => setPage('fees-options')} feeCollections={feeCollections} onDelete={handleDeleteFeeCollection} onUpdate={handleUpdateFeeCollection} isDemoMode={isDemoMode} />;

            case 'fee-dues-list':
                return <FeeDuesListPage onBack={() => setPage('fees-options')} students={students} batches={batches} feeCollections={feeCollections} academy={academy!} />;

            case 'staff-options':
                return <StaffOptionsPage onBack={() => setPage('dashboard')} onNavigate={setPage} />;

            case 'staff-manager':
                return <StaffManagerPage onBack={() => setPage('staff-options')} staff={staff} onManageAccess={(id) => { setSelectedStaffId(id); setPage('staff-batch-access'); }} onShowDevPopup={handleShowDevPopup} onToggleStatus={handleToggleStaffStatus} />;

            case 'new-staff':
                return <NewStaffPage onBack={() => setPage('staff-options')} onSave={handleSaveStaff} staff={staff} />;

            case 'inactive-staff':
                return <InactiveStaffPage onBack={() => setPage('staff-options')} staff={staff} onToggleStatus={handleToggleStaffStatus} />;

            case 'staff-batch-access':
                const accessStaff = staff.find(s => s.id === selectedStaffId);
                if (accessStaff) return <StaffBatchAccessPage onBack={() => setPage('staff-manager')} staff={accessStaff} batches={batches} onSave={handleUpdateStaffBatchAccess} />;
                return null;

            case 'mark-staff-attendance':
                return <MarkStaffAttendancePage onBack={() => setPage('staff-options')} batches={batches} staff={staff} academyId={academy!.id} isDemoMode={isDemoMode} staffAttendance={staffAttendance} onSave={handleSaveStaffAttendance} onDelete={handleDeleteStaffAttendance} />;

            case 'staff-attendance-report':
                return <StaffAttendanceReportPage onBack={() => setPage('staff-options')} staff={staff} staffAttendance={staffAttendance} />;

            case 'manage-salaries':
                return <ManageSalariesPage onBack={() => setPage('staff-options')} staff={staff} salaryPayments={salaryPayments} onSave={handleSaveSalaryPayment} onDelete={handleDeleteSalaryPayment} isDemoMode={isDemoMode} />;

            case 'my-account':
                return <MyAccountPage onBack={() => setPage('dashboard')} onSave={handleSaveAcademyDetails} onLogout={handleLogout} academy={academy!} />;

            case 'schedule-classes':
                return <ScheduleClassesPage onBack={() => setPage('dashboard')} batches={batches} staff={staff} onSave={handleSaveSchedule} academyId={academy!.id} isDemoMode={isDemoMode} />;

            case 'subscription':
                return <SubscriptionPage onBack={() => setPage('dashboard')} academy={academy!} onSubscribe={handleSubscribe} />;

            case 'subscription-expired':
                return <SubscriptionExpiredPage onNavigate={setPage} onLogout={handleLogout} academy={academy!} onSubscribe={handleSubscribe} />;

            case 'income-expenses':
                return <IncomeExpensesPage onBack={() => setPage('dashboard')} transactions={transactions} isDemoMode={isDemoMode} onSave={handleSaveTransaction} onUpdate={handleUpdateTransaction} onDelete={handleDeleteTransaction} />;

            case 'manage-exams':
                return <ManageExamsPage onBack={() => setPage('dashboard')} exams={exams} onNavigate={handleNavigate} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} onPublish={handlePublishExam} />;

            case 'create-exam':
                const examToEdit = selectedExamId ? exams.find(e => e.id === selectedExamId) : undefined;
                return <CreateExamPage onBack={() => { setSelectedExamId(null); setPage('manage-exams'); }} onSave={handleSaveExam} batches={batches} exam={examToEdit} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;

            case 'record-marks':
                const examForMarks = exams.find(e => e.id === (selectedExamId || pageParams.examId));
                if (examForMarks) return <RecordMarksPage onBack={() => setPage('manage-exams')} exam={examForMarks} students={students} academy={academy!} isDemoMode={isDemoMode} onPublish={handlePublishExam} />;
                return null;

            case 'enquiry-manager':
                return <EnquiryManagerPage onBack={() => setPage('dashboard')} enquiries={enquiries} onNavigate={handleNavigate} onDelete={handleDeleteEnquiry} onUpdateStatus={handleSaveEnquiry} />;

            case 'new-enquiry':
                return <NewEnquiryPage onBack={() => setPage('enquiry-manager')} onSave={handleSaveEnquiry} batches={batches} />;

            case 'edit-enquiry':
                const enquiryToEdit = enquiries.find(e => e.id === pageParams.enquiryId);
                return <NewEnquiryPage onBack={() => setPage('enquiry-manager')} onSave={handleSaveEnquiry} batches={batches} enquiry={enquiryToEdit} />;

            case 'reports-options':
                return <ReportsPage onBack={() => setPage('dashboard')} onNavigate={setPage} onShowDevPopup={handleShowDevPopup} />;

            case 'attendance-report':
                return <AttendanceReportPage onBack={() => setPage('reports-options')} batches={batches} students={students} academyId={academy!.id} academy={academy!} />;

            case 'study-material':
                return <StudyMaterialPage onBack={() => setPage('dashboard')} materials={studyMaterials} batches={batches} onNavigate={handleNavigate} onDelete={handleDeleteStudyMaterial} />;

            case 'upload-study-material':
                return <UploadStudyMaterialPage onBack={() => setPage('study-material')} onSave={handleSaveStudyMaterial} batches={batches} academyId={academy!.id} uploaderName={currentUser?.role === 'admin' ? academy!.name : currentUser!.data.name} isDemoMode={isDemoMode} />;

            case 'edit-study-material':
                const materialToEdit = studyMaterials.find(m => m.id === pageParams.studyMaterialId);
                return <UploadStudyMaterialPage onBack={() => setPage('study-material')} onSave={handleSaveStudyMaterial} batches={batches} academyId={academy!.id} uploaderName={currentUser?.role === 'admin' ? academy!.name : currentUser!.data.name} materialToEdit={materialToEdit} isDemoMode={isDemoMode} />;

            case 'homework':
                return <HomeworkPage onBack={() => setPage('dashboard')} homework={homework} batches={batches} onNavigate={handleNavigate} onDelete={handleDeleteHomework} />;

            case 'assign-homework':
                return <AssignHomeworkPage onBack={() => setPage('homework')} onSave={handleSaveHomework} batches={batches} academyId={academy!.id} uploaderName={currentUser?.role === 'admin' ? academy!.name : currentUser!.data.name} isDemoMode={isDemoMode} />;

            case 'edit-homework':
                const homeworkToEdit = homework.find(h => h.id === pageParams.homeworkId);
                return <AssignHomeworkPage onBack={() => setPage('homework')} onSave={handleSaveHomework} batches={batches} academyId={academy!.id} uploaderName={currentUser?.role === 'admin' ? academy!.name : currentUser!.data.name} homeworkToEdit={homeworkToEdit} isDemoMode={isDemoMode} />;

            case 'homework-submissions':
                const hwForSubs = homework.find(h => h.id === pageParams.homeworkId);
                if (hwForSubs) return <HomeworkSubmissionsPage onBack={() => setPage('homework')} homework={hwForSubs} students={students} academyId={academy!.id} />;
                return null;

            case 'manage-quizzes':
                return <ManageQuizzesPage onBack={() => setPage('dashboard')} quizzes={quizzes} onNavigate={handleNavigate} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} onDelete={handleDeleteQuiz} onShowDevPopup={handleShowDevPopup} />;

            case 'create-quiz':
                return <CreateQuizPage onBack={() => setPage('manage-quizzes')} onSave={handleSaveQuiz} batches={batches} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;

            case 'edit-quiz':
                const quizToEdit = quizzes.find(q => q.id === pageParams.quizId);
                return <CreateQuizPage onBack={() => setPage('manage-quizzes')} onSave={handleSaveQuiz} batches={batches} quiz={quizToEdit} staffPermissions={currentUser?.role === 'staff' ? currentUser.data.batchAccess : undefined} />;

            case 'quiz-results':
                const quizForResults = quizzes.find(q => q.id === pageParams.quizId);
                if (quizForResults) return <QuizResultsPage onBack={() => setPage('manage-quizzes')} quiz={quizForResults} submissions={quizSubmissions.filter(s => s.id.startsWith(quizForResults.id))} students={students} />;
                return null;

            case 'leave-manager':
                return <LeaveManagerPage onBack={() => setPage('dashboard')} leaveRequests={leaveRequests} students={students} staff={staff} currentUser={currentUser!} batches={batches} onUpdateStatus={handleUpdateLeaveStatus} />;

            case 'todo-task':
                return <TodoTaskPage onBack={() => setPage('dashboard')} tasks={tasks} staff={staff} onSaveTask={handleSaveTask} onToggleTaskStatus={handleToggleTaskStatus} onDeleteTask={handleDeleteTask} isDemoMode={isDemoMode} />;

            case 'notice-board':
                return <NoticeBoardPage onBack={() => setPage('dashboard')} notices={notices} onSaveNotice={handleSaveNotice} onDeleteNotice={handleDeleteNotice} isDemoMode={isDemoMode} academyId={academy!.id} />;

            case 'notifications':
                return <NotificationsPage onBack={() => setPage('dashboard')} enquiries={enquiries.filter(e => e.status === 'New')} leaveRequests={leaveRequests.filter(l => l.status === 'Pending')} unmarkedAttendanceBatches={[]} scheduleAlerts={[]} onNavigate={setPage} />;

            case 'transport-options':
                return <TransportOptionsPage onBack={() => setPage('dashboard')} onCreate={() => setPage('new-transport-route')} routes={transportRoutes} onNavigate={handleNavigate} onDelete={handleDeleteTransportRoute} />;

            case 'new-transport-route':
                return <NewTransportRoutePage onBack={() => setPage('transport-options')} onSave={handleSaveTransportRoute} />;

            case 'edit-transport-route':
                const routeToEdit = transportRoutes.find(r => r.id === pageParams.routeId);
                if (routeToEdit) return <EditTransportRoutePage onBack={() => setPage('transport-options')} onSave={handleSaveTransportRoute} route={routeToEdit} />;
                return null;

            case 'map-students-to-route':
                const mapRoute = transportRoutes.find(r => r.id === pageParams.routeId);
                if (mapRoute) return <MapStudentsToRoutePage onBack={() => setPage('transport-options')} route={mapRoute} students={students} onSave={handleMapStudentsToRoute} />;
                return null;

            case 'settings':
                return <SettingsPage onBack={() => setPage('dashboard')} onNavigate={setPage} onShowDevPopup={handleShowDevPopup} />;

            case 'custom-sms-settings':
                return <CustomSmsSettingsPage onBack={() => setPage('settings')} academy={academy!} onSave={handleSaveAcademyDetails} />;

            case 'legal':
                return <LegalPage onBack={() => setPage('dashboard')} />;

            // Student specific pages
            case 'my-academy':
                return academy && <MyAcademyPage academy={academy} onBack={() => setPage('dashboard')} />;
            case 'timetable':
                return student && <StudentTimetablePage onBack={() => setPage('dashboard')} student={student} academyId={academy!.id} batches={batches} />;
            case 'attendance':
                return student && <StudentAttendancePage student={student} academyId={academy!.id} onBack={() => setPage('dashboard')} />;
            case 'fee-status':
                return student && <StudentFeeStatusPage student={student} feeCollections={feeCollections.filter(f => f.studentId === student.id)} onBack={() => setPage('dashboard')} />;
            case 'student-exams':
                return student && <StudentExamsPage onBack={() => setPage('dashboard')} student={student} academyId={academy!.id} />;
            case 'student-study-material':
                return student && <StudentStudyMaterialPage onBack={() => setPage('dashboard')} materials={studyMaterials} student={student} />;
            case 'student-homework':
                return student && <StudentHomeworkPage onBack={() => setPage('dashboard')} homework={homework} student={student} academyId={academy!.id} batches={batches} isDemoMode={isDemoMode} />;
            case 'student-quizzes':
                return student && <StudentQuizzesPage onBack={() => setPage('dashboard')} quizzes={quizzes} student={student} onNavigate={handleNavigate} academyId={academy!.id} />;
            case 'take-quiz':
                const quizToTake = quizzes.find(q => q.id === pageParams.quizId);
                return (student && quizToTake) && <TakeQuizPage onBack={() => setPage('student-quizzes')} quiz={quizToTake} onSaveSubmission={handleSaveQuizSubmission} studentId={student.id} academyId={academy!.id} />;
            case 'quiz-result':
                const quizForResult = quizzes.find(q => q.id === pageParams.quizId);
                return (student && quizForResult) && <QuizResultPage onBack={() => setPage('student-quizzes')} quiz={quizForResult} studentId={student.id} academyId={academy!.id} />;
            case 'my-leave':
                return <MyLeavePage onBack={() => setPage('dashboard')} onNavigate={setPage} currentUser={currentUser!} leaveRequests={leaveRequests} />;
            case 'apply-leave':
                return <ApplyLeavePage onBack={() => setPage('my-leave')} onSave={async (d) => {}} currentUser={currentUser!} academyId={academy!.id} isDemoMode={isDemoMode} />;
            case 'student-notice-board':
                return <StudentNoticeBoardPage onBack={() => setPage('dashboard')} notices={notices} />;
            case 'student-transport':
                return student && <StudentTransportPage onBack={() => setPage('dashboard')} student={student} transportRoutes={transportRoutes} />;

            // Staff specific pages
            case 'staff-attendance':
                return currentUser?.role === 'staff' && <StaffAttendancePage onBack={() => setPage('dashboard')} staff={currentUser.data} staffAttendance={staffAttendance} />;
            case 'staff-notice-board':
                return <StaffNoticeBoardPage onBack={() => setPage('dashboard')} notices={notices} />;
            case 'staff-notifications':
                return <StaffNotificationsPage onBack={() => setPage('dashboard')} pendingLeaves={leaveRequests.filter(l => l.status === 'Pending')} onNavigate={setPage} />;
            case 'staff-salary':
                return currentUser?.role === 'staff' && <StaffSalaryPage onBack={() => setPage('dashboard')} staff={currentUser.data} salaryPayments={salaryPayments} />;
            case 'class-schedule':
                return currentUser?.role === 'staff' && <StaffSchedulePage onBack={() => setPage('dashboard')} staff={currentUser.data} academyId={academy!.id} />;

            default:
                if (currentUser.role === 'admin') return <Dashboard onNavigate={setPage} academy={academy!} students={students} batches={batches} staff={staff} transactions={transactions} onShowDevPopup={handleShowDevPopup} />;
                if (currentUser.role === 'student') return <StudentDashboardPage student={currentUser.data} academy={academy!} feeCollections={feeCollections} batches={batches} onNavigate={setPage} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                if (currentUser.role === 'staff') return <StaffDashboardPage onNavigate={setPage} academy={academy!} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} isDemoMode={isDemoMode} />;
                return null;
        }
    };

    const MainLayout: React.FC<{ children: React.ReactNode }> = ({ children }) => (
        <div className={`min-h-screen font-sans ${theme} bg-gray-100 dark:bg-gray-900`}>
            {isPlaceholderConfig && page !== 'onboarding' && <ConfigurationWarning />}
            {connectionError && <ConnectionErrorBanner message={connectionError} onClose={() => setConnectionError(null)} />}
            {isOffline && <OfflineIndicator />}

            {currentUser?.role === 'admin' && academy && (
                 <>
                     {page === 'dashboard' && <Header academy={academy} onLogout={handleLogout} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onNavigate={setPage} notificationCount={0} />}
                     <SideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} />
                     <main>{children}</main>
                     {page === 'dashboard' && <BottomNav onNavigate={setPage} activePage={page} onOpenChatbot={() => setIsChatbotOpen(true)} />}
                 </>
            )}

            {currentUser?.role === 'student' && academy && (
                <>
                    <StudentSideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} systemLogoUrl={systemLogoUrl} />
                    <main>{children}</main>
                </>
            )}

            {currentUser?.role === 'staff' && academy && (
                <>
                    {page === 'dashboard' && <StaffHeader staffName={currentUser.data.name} academyName={academy.name} onLogout={handleLogout} onToggleNav={() => setIsNavOpen(true)} theme={theme} onToggleTheme={handleToggleTheme} onNavigate={setPage} notificationCount={0} />}
                    <StaffSideNav isOpen={isNavOpen} onClose={() => setIsNavOpen(false)} onNavigate={setPage} onLogout={handleLogout} staff={currentUser.data} onShowDevPopup={handleShowDevPopup} systemLogoUrl={systemLogoUrl} />
                    <main>{children}</main>
                </>
            )}

            {showConsent && <DataConsentModal onAccept={() => { localStorage.setItem('dataConsentAccepted', 'true'); setShowConsent(false); }} />}
            {showDevPopup && <DevInProgressPopup featureName={showDevPopup} onClose={() => setShowDevPopup(null)} />}
            {imageToView && <FullScreenImageViewer src={imageToView} alt="Full screen view" onClose={() => setImageToView(null)} />}
             {isChatbotOpen && academy && (
                <AIChatbot
                    isOpen={isChatbotOpen}
                    onClose={() => setIsChatbotOpen(false)}
                    onNavigate={(page: string) => {
                        handleNavigate(page);
                        setIsChatbotOpen(false);
                    }}
                    students={students}
                    feeCollections={feeCollections}
                    batches={batches}
                    academyId={academy.id}
                />
            )}
        </div>
    );

    if (isLoading) return <SplashScreen />;

    if (!currentUser) {
         if (page === 'onboarding') return <OnboardingPage onComplete={() => { localStorage.setItem('onboardingCompleted', 'true'); setPage('role-selection'); }} />;
         if (page === 'role-selection') return <RoleSelectionPage onSelectRole={(role) => { setLoginPageRole(role); setPage('login'); }} onBack={() => { if(window.history.length > 1) window.history.back(); }} />;
         if (page === 'register') return <RegisterPage onNavigateToLogin={() => setPage('login')} />;
         if (page === 'complete-registration') return <CompleteRegistrationPage onComplete={async () => {}} onLogout={handleLogout} userEmail="" externalError={null} clearExternalError={() => {}} />;
         return <LoginPage onLogin={handleLogin} onNavigateToRegister={() => setPage('register')} externalError={authError} clearExternalError={() => setAuthError(null)} initialRole={loginPageRole} onGoBack={() => setPage('role-selection')} systemLogoUrl={systemLogoUrl} />;
    }

    return <MainLayout>{renderPage()}</MainLayout>;
}
